+async function* executeDelegation(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  ancestry: string[],
+): AsyncGenerator<StreamResponse, DelegationResult> {
+  if (!agentId || !globalRegistry.getAgent(agentId) || !globalRegistry.getProviderForAgent(agentId)) {
+    const content = `Agent '${agentId}' not found or provider not available`;
+    yield { type: "error", error: content };
+    return { content, isError: true };
+  }
+
+  if (ancestry.includes(agentId)) {
+    const content = `Circular delegation detected for agent '${agentId}'`;
+    yield { type: "error", error: content };
+    return { content, isError: true };
+  }
+
+  const delegatedRequest: ChatRequest = {
+    ...request,
+    message: instructions,
+  };
+  const run = executeAgentTurns(agentId, delegatedRequest, null, abortController, debugMode, [...ancestry, agentId], false);
+  let next = await run.next();
+  while (!next.done) {
+    // Nested tool calls still need to be observable so their result can be matched.
+    yield next.value;
+    next = await run.next();
+  }
+  return next.value;
+}
